export type ImageSize = '1K' | '2K' | '4K';

export interface Page {
  text: string;
  imagePrompt: string;
  imageUrl?: string;
  audioData?: string;
}

export interface Story {
  title: string;
  pages: Page[];
}

export interface ChatMessage {
