}

export interface AppState {
  apiKeySelected: boolean;
  isGenerating: boolean;
  currentStory: Story | null;
  currentPageIndex: number;
  imageSize: ImageSize;
}

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Story, ImageSize } from "./types";

// Helper to decode base64 to bytes
export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Helper to decode PCM data
export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export class GeminiService {
  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async generateStoryStructure(prompt: string): Promise<Story> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create a charming children's story based on: "${prompt}". 
      Return the story as a JSON object with a title and exactly 5 pages. 
      Each page must have "text" (max 3 sentences) and an "imagePrompt" (a detailed descriptive prompt for a kid-friendly illustration).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            pages: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  imagePrompt: { type: Type.STRING }
                },
                required: ["text", "imagePrompt"]
              }
            }
          },
          required: ["title", "pages"]
        }
      }
    });

    return JSON.parse(response.text || '{}') as Story;
  }

  async generateImage(prompt: string, size: ImageSize): Promise<string> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [{ text: `A magical children's book illustration: ${prompt}. Soft colors, high quality, whimsical style.` }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: size
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("Failed to generate image");
  }

  async generateSpeech(text: string): Promise<string> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Read this story page with a warm, friendly, and expressive voice: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' } // Kore is friendly
          }
        }
      }
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Failed to generate speech");
    return base64Audio;
  }

  async chatWithGemini(userMessage: string, chatHistory: any[]): Promise<string> {
    const ai = this.getAI();
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: {
        systemInstruction: "You are a friendly, magical storybook helper. Answer children's questions about stories and magic in a kind, simple, and encouraging way. Keep responses short and sweet.",
      }
    });

    // We don't send history yet to keep it simple, but we could
    const response = await chat.sendMessage({ message: userMessage });
    return response.text || "I'm not sure what to say, but I'm happy to be here!";
  }
}

export const gemini = new GeminiService();

import React, { useState, useEffect, useCallback } from 'react';
import { AppState, Story, ImageSize } from './types';
import LandingPage from './components/LandingPage';
import StoryWizard from './components/StoryWizard';
import StoryReader from './components/StoryReader';
import ChatBot from './components/ChatBot';
import { gemini } from './geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    apiKeySelected: false,
    isGenerating: false,
    currentStory: null,
    currentPageIndex: 0,
    imageSize: '1K',
  });

  const [showChat, setShowChat] = useState(false);

  // Check initial key state
  useEffect(() => {
    const checkKey = async () => {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (hasKey) setState(prev => ({ ...prev, apiKeySelected: true }));
    };
    checkKey();
  }, []);

  const handleStart = async () => {
    // @ts-ignore
    await window.aistudio.openSelectKey();
    setState(prev => ({ ...prev, apiKeySelected: true }));
  };

  const generateStory = async (userPrompt: string) => {
    setState(prev => ({ ...prev, isGenerating: true, currentStory: null, currentPageIndex: 0 }));
    try {
      const storyStructure = await gemini.generateStoryStructure(userPrompt);

      // Load first page immediately
      const firstPage = storyStructure.pages[0];
      const imageUrl = await gemini.generateImage(firstPage.imagePrompt, state.imageSize);
      const audioData = await gemini.generateSpeech(firstPage.text);

      storyStructure.pages[0] = { ...firstPage, imageUrl, audioData };

      setState(prev => ({ 
        ...prev, 
        currentStory: storyStructure, 
        isGenerating: false 
      }));

      // Background load other pages
      loadRemainingPages(storyStructure);
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isGenerating: false }));
      alert("Oh no! Magic failed. Check if you have a valid API key selected.");
    }
  };

  const loadRemainingPages = async (story: Story) => {
    const updatedPages = [...story.pages];
    for (let i = 1; i < updatedPages.length; i++) {
      try {
        const imageUrl = await gemini.generateImage(updatedPages[i].imagePrompt, state.imageSize);
        const audioData = await gemini.generateSpeech(updatedPages[i].text);
        updatedPages[i] = { ...updatedPages[i], imageUrl, audioData };

        setState(prev => {
          if (!prev.currentStory) return prev;
          const newStory = { ...prev.currentStory, pages: updatedPages };
          return { ...prev, currentStory: newStory };
        });
      } catch (err) {
        console.warn(`Failed to load page ${i}`, err);
      }
    }
  };

  if (!state.apiKeySelected) {
    return <LandingPage onStart={handleStart} />;
  }

  return (
    <div className="min-h-screen relative flex flex-col bg-gradient-to-br from-indigo-100 via-purple-50 to-pink-100">
      <header className="p-4 flex justify-between items-center z-10">
        <h1 
          className="text-3xl font-magic text-indigo-600 cursor-pointer drop-shadow-sm"
          onClick={() => setState(prev => ({ ...prev, currentStory: null }))}
        >
          ✨ Magic Storybook
        </h1>

        <div className="flex items-center gap-4">
          <select 
            value={state.imageSize}
            onChange={(e) => setState(prev => ({ ...prev, imageSize: e.target.value as ImageSize }))}
            className="bg-white/80 border border-indigo-200 rounded-full px-4 py-1 text-sm font-semibold text-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-400"
          >
            <option value="1K">1K Quality</option>
            <option value="2K">2K Quality</option>
            <option value="4K">4K Quality</option>
          </select>

          <button 
            onClick={() => setShowChat(!showChat)}
            className="p-2 bg-white/90 hover:bg-white rounded-full shadow-md text-indigo-600 transition-transform hover:scale-110 active:scale-95"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
            </svg>
          </button>
        </div>
      </header>

      <main className="flex-1 flex flex-col items-center justify-center p-4">
        {!state.currentStory && !state.isGenerating && (
          <StoryWizard onGenerate={generateStory} />
        )}

        {state.isGenerating && (
          <div className="flex flex-col items-center gap-6 animate-pulse">
            <div className="w-24 h-24 bg-indigo-400 rounded-full flex items-center justify-center text-5xl">📖</div>
            <p className="text-2xl font-magic text-indigo-700 text-center">
              Mixing the magic ink... <br/>
              <span className="text-lg font-sans text-indigo-500 font-medium">Creating your custom story and illustrations!</span>
            </p>
          </div>
        )}

        {state.currentStory && (
          <StoryReader 
            story={state.currentStory} 
            currentIndex={state.currentPageIndex}
            onPageChange={(idx) => setState(prev => ({ ...prev, currentPageIndex: idx }))}
          />
        )}
      </main>

      {showChat && <ChatBot onClose={() => setShowChat(false)} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';

interface Props {
  onGenerate: (prompt: string) => void;
}

const StoryWizard: React.FC<Props> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [isFocused, setIsFocused] = useState(false);

  const suggestions = [
    "A brave kitten who wanted to fly",
    "A robot that learned how to garden",
    "A journey to the moon made of cheese",
    "The secret life of my teddy bear"
  ];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (prompt.trim()) {
      onGenerate(prompt);
    }
  };

  return (
    <div className="w-full max-w-2xl bg-white/60 backdrop-blur-md rounded-[3rem] p-10 shadow-xl border border-white/50">
      <h2 className="text-3xl font-magic text-indigo-700 mb-2 text-center">What shall we imagine today?</h2>
      <p className="text-indigo-500 text-center mb-10 font-medium italic">Type your story idea below!</p>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div className={`relative transition-all duration-300 ${isFocused ? 'scale-[1.02]' : ''}`}>
          <textarea
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            placeholder="A friendly dragon who loves marshmallows..."
            className="w-full h-32 bg-white rounded-3xl p-6 text-xl text-indigo-900 placeholder:text-indigo-200 border-2 border-transparent focus:border-indigo-400 focus:outline-none shadow-inner resize-none"
          />
          <div className="absolute -top-4 -right-4 text-4xl">✍️</div>
        </div>

        <div className="flex flex-wrap gap-3 justify-center">
          {suggestions.map((s, i) => (
            <button
              key={i}
              type="button"
              onClick={() => setPrompt(s)}
