};

export default StoryWizard;

import React, { useState, useEffect, useRef } from 'react';
import { Story } from '../types';
import { decodeBase64, decodeAudioData } from '../geminiService';

interface Props {
  story: Story;
  currentIndex: number;
  onPageChange: (index: number) => void;
}

const StoryReader: React.FC<Props> = ({ story, currentIndex, onPageChange }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const currentPage = story.pages[currentIndex];
  const totalPages = story.pages.length;

  const handleNext = () => {
    if (currentIndex < totalPages - 1) onPageChange(currentIndex + 1);
  };

  const handlePrev = () => {
    if (currentIndex > 0) onPageChange(currentIndex - 1);
  };

  // Touch handling for swipe
  const touchStartX = useRef<number | null>(null);
  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
  };
  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStartX.current) return;
    const diff = touchStartX.current - e.changedTouches[0].clientX;
    if (diff > 50) handleNext();
    else if (diff < -50) handlePrev();
    touchStartX.current = null;
  };

  const playAudio = async () => {
    if (!currentPage.audioData) return;

    // Stop previous audio
    if (currentSourceRef.current) {
      currentSourceRef.current.stop();
    }

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }

    const ctx = audioContextRef.current;
    if (ctx.state === 'suspended') await ctx.resume();

    try {
      setIsPlaying(true);
      const data = decodeBase64(currentPage.audioData);
      const buffer = await decodeAudioData(data, ctx, 24000, 1);
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.onended = () => setIsPlaying(false);
      source.start();
      currentSourceRef.current = source;
    } catch (err) {
      console.error("Audio playback error", err);
      setIsPlaying(false);
    }
  };

  useEffect(() => {
    // Auto-play when page changes if desired, or just reset state
    setIsPlaying(false);
    if (currentSourceRef.current) {
      currentSourceRef.current.stop();
    }
  }, [currentIndex]);

  return (
    <div 
      className="w-full max-w-5xl h-[80vh] flex flex-col md:flex-row bg-white rounded-[3rem] shadow-2xl overflow-hidden border-8 border-indigo-100 relative group"
      onTouchStart={handleTouchStart}
      onTouchEnd={handleTouchEnd}
    >
      {/* Navigation Arrows */}
      {currentIndex > 0 && (
        <button 
          onClick={handlePrev}
          className="absolute left-4 top-1/2 -translate-y-1/2 z-20 p-4 bg-white/80 hover:bg-white rounded-full shadow-lg text-indigo-600 transition-transform hover:scale-110 active:scale-90 opacity-0 group-hover:opacity-100 hidden md:block"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" />
          </svg>
        </button>
      )}

      {currentIndex < totalPages - 1 && (
        <button 
          onClick={handleNext}
          className="absolute right-4 top-1/2 -translate-y-1/2 z-20 p-4 bg-white/80 hover:bg-white rounded-full shadow-lg text-indigo-600 transition-transform hover:scale-110 active:scale-90 opacity-0 group-hover:opacity-100 hidden md:block"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" />
          </svg>
        </button>
      )}

      {/* Image Panel */}
      <div className="flex-1 bg-indigo-50 relative overflow-hidden flex items-center justify-center">
        {currentPage.imageUrl ? (
          <img 
            src={currentPage.imageUrl} 
            alt="Story illustration" 
            className="w-full h-full object-cover transition-opacity duration-700 ease-in-out"
          />
        ) : (
          <div className="flex flex-col items-center gap-4 text-indigo-300">
            <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-300 border-t-transparent" />
            <p className="font-magic">Painting illustration...</p>
          </div>
        )}
      </div>

      {/* Text Panel */}
      <div className="flex-1 flex flex-col p-10 md:p-14 justify-between bg-white md:border-l-4 border-indigo-100">
        <div>
          <h3 className="text-indigo-300 font-magic text-sm uppercase tracking-widest mb-6">Page {currentIndex + 1} of {totalPages}</h3>
          <p className="text-2xl md:text-3xl font-medium leading-relaxed text-indigo-900 selection:bg-indigo-100">
            {currentPage.text}
          </p>
        </div>

        <div className="flex flex-col gap-6">
          <button
            onClick={playAudio}
            disabled={!currentPage.audioData || isPlaying}
            className={`flex items-center justify-center gap-3 py-4 px-8 rounded-2xl font-bold transition-all shadow-md ${
              isPlaying 
                ? 'bg-indigo-100 text-indigo-400 cursor-default' 
                : 'bg-indigo-600 hover:bg-indigo-700 text-white hover:shadow-xl active:scale-95'
            }`}
          >
            {isPlaying ? (
              <>
                <div className="flex gap-1 items-end h-4">
                  <div className="w-1 bg-indigo-400 rounded-full animate-[bounce_0.6s_infinite_0s]" />
                  <div className="w-1 bg-indigo-400 rounded-full animate-[bounce_0.6s_infinite_0.1s]" />
                  <div className="w-1 bg-indigo-400 rounded-full animate-[bounce_0.6s_infinite_0.2s]" />
                </div>
                <span>Reading Aloud...</span>
              </>
            ) : (
              <>
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.983 5.983 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.984 3.984 0 00-1.172-2.828a1 1 0 010-1.415z" clipRule="evenodd" />
                </svg>
                <span>Read to Me</span>
              </>
            )}
          </button>

          <div className="flex justify-between items-center text-xs text-indigo-300 font-bold">
            <span className="cursor-pointer hover:text-indigo-500" onClick={handlePrev}>← PREVIOUS</span>
            <div className="flex gap-2">
              {story.pages.map((_, i) => (
                <div key={i} className={`w-2 h-2 rounded-full transition-colors ${i === currentIndex ? 'bg-indigo-500' : 'bg-indigo-100'}`} />
              ))}
            </div>
            <span className="cursor-pointer hover:text-indigo-500" onClick={handleNext}>NEXT →</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StoryReader;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { gemini } from '../geminiService';

interface Props {
  onClose: () => void;
}

const ChatBot: React.FC<Props> = ({ onClose }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Hi! I am your Storybook Helper. Do you have a question about magic or stories?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const response = await gemini.chatWithGemini(userMsg, messages);
      setMessages(prev => [...prev, { role: 'model', text: response }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: 'model', text: "Sorry, my magic is acting up. Could you ask again?" }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 w-[90vw] max-w-sm h-[500px] bg-white rounded-[2.5rem] shadow-2xl flex flex-col z-50 border-4 border-indigo-100 overflow-hidden transform animate-[bounceIn_0.5s_ease-out]">
      <header className="bg-indigo-600 p-5 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-xl">🧙‍♂️</div>
          <span className="text-white font-magic tracking-wide">Magic Helper</span>
        </div>
        <button onClick={onClose} className="text-white hover:text-indigo-200 p-1">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </header>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-[1.5rem] text-sm font-medium shadow-sm ${
              m.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-indigo-50 text-indigo-900 rounded-tl-none'
            }`}>
              {m.text}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-indigo-50 p-4 rounded-[1.5rem] rounded-tl-none shadow-sm flex gap-1">
              <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full animate-bounce" />
              <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full animate-bounce [animation-delay:0.2s]" />
              <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full animate-bounce [animation-delay:0.4s]" />
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSend} className="p-4 bg-indigo-50">
        <div className="relative">
          <input
            type="text"
            value={input}
