    setIsLoading(true);

    try {
      const response = await gemini.chatWithGemini(userMsg, messages);
      setMessages(prev => [...prev, { role: 'model', text: response }]);
    } catch (err) {
      setMessages(prev => [...prev, { role: 'model', text: "Oops! My magic wand is out of batteries. Try again?" }]);
    } finally {
      setIsLoading(false);
    }
