  return (
    <div className="fixed inset-0 z-[100] md:inset-auto md:bottom-6 md:right-6 md:w-[380px] md:h-[600px] flex flex-col bg-white md:rounded-[2.5rem] shadow-2xl overflow-hidden animate-[popIn_0.4s_cubic-bezier(0.175,0.885,0.32,1.275)]">
