import { AppState, Story, ImageSize } from './types';
import LandingPage from './components/LandingPage';
import StoryWizard from './components/StoryWizard';
import StoryReader from './components/StoryReader';
import InfoPanel from './components/InfoPanel';
import { gemini } from './geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    apiKeySelected: false,
    isGenerating: false,
    currentStory: null,
    currentPageIndex: 0,
    imageSize: '1K',
  });

  const [showInfo, setShowInfo] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (hasKey) setState(prev => ({ ...prev, apiKeySelected: true }));
    };
    checkKey();
  }, []);

  const handleStart = async () => {
    // @ts-ignore
    await window.aistudio.openSelectKey();
    setState(prev => ({ ...prev, apiKeySelected: true }));
  };

  const generateStory = async (userPrompt: string, pageCount: number) => {
    setState(prev => ({ ...prev, isGenerating: true, currentStory: null, currentPageIndex: 0 }));
    try {
      const storyStructure = await gemini.generateStoryStructure(userPrompt, pageCount);
      const firstPage = storyStructure.pages[0];
      const imageUrl = await gemini.generateImage(firstPage.imagePrompt, state.imageSize);
      const audioData = await gemini.generateSpeech(firstPage.text);

      storyStructure.pages[0] = { ...firstPage, imageUrl, audioData };

      setState(prev => ({ 
        ...prev, 
        currentStory: storyStructure, 
        isGenerating: false 
      }));

      loadRemainingPages(storyStructure);
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isGenerating: false }));
      alert("Magic took a nap! Please try again or check your API key.");
    }
  };

  const loadRemainingPages = async (story: Story) => {
    const updatedPages = [...story.pages];
    for (let i = 1; i < updatedPages.length; i++) {
      try {
        const imageUrl = await gemini.generateImage(updatedPages[i].imagePrompt, state.imageSize);
        const audioData = await gemini.generateSpeech(updatedPages[i].text);
        updatedPages[i] = { ...updatedPages[i], imageUrl, audioData };

        setState(prev => {
          if (!prev.currentStory) return prev;
          return { ...prev, currentStory: { ...prev.currentStory, pages: updatedPages } };
        });
      } catch (err) {
        console.warn(`Failed to load page ${i}`, err);
      }
    }
  };

  if (!state.apiKeySelected) {
    return <LandingPage onStart={handleStart} />;
  }

  return (
    <div className="h-full flex flex-col relative overflow-hidden bg-white">
      {/* Global magical background elements */}
      <div className="absolute top-0 right-0 w-[50%] h-[40%] bg-indigo-50/50 blur-[120px] rounded-full pointer-events-none -z-10" />
      <div className="absolute bottom-0 left-0 w-[40%] h-[30%] bg-purple-50/50 blur-[100px] rounded-full pointer-events-none -z-10" />

      <header className="px-5 py-3 md:py-4 flex justify-between items-center bg-white/60 backdrop-blur-md border-b border-indigo-50/50 flex-shrink-0 z-50">
        <div 
          className="flex items-center gap-2 cursor-pointer group"
          onClick={() => setState(prev => ({ ...prev, currentStory: null }))}
        >
          <div className="flex flex-col">
            <h1 className="text-lg md:text-xl font-magic text-indigo-700 leading-none">Magic</h1>
            <h1 className="text-lg md:text-xl font-magic text-indigo-700 leading-none">Storybook</h1>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <div className="hidden sm:block">
            <select 
              value={state.imageSize}
              onChange={(e) => setState(prev => ({ ...prev, imageSize: e.target.value as ImageSize }))}
              className="bg-white border border-indigo-100 rounded-full px-4 py-1.5 text-xs font-bold text-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-400 cursor-pointer shadow-sm"
            >
              <option value="1K">1K Quality</option>
              <option value="2K">2K Quality</option>
              <option value="4K">4K Quality</option>
            </select>
          </div>

          <button 
            onClick={() => setShowInfo(!showInfo)}
            className="p-2 md:p-2.5 bg-white border border-indigo-100 rounded-2xl shadow-sm text-indigo-600 hover:shadow-md active:scale-90 transition-all flex items-center justify-center"
            aria-label="App Information"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>
        </div>
      </header>

      <main className="flex-1 relative overflow-y-auto scrollbar-hide px-4 py-2 sm:py-6 md:px-8 flex flex-col items-center">
        <div className="w-full max-w-4xl h-full min-h-0 flex flex-col items-center justify-start sm:justify-center">
          {!state.currentStory && !state.isGenerating && (
            <StoryWizard onGenerate={generateStory} />
          )}

          {state.isGenerating && (
            <div className="flex flex-col items-center gap-8 py-12 animate-pulse">
              <div className="relative">
                <div className="w-28 h-28 bg-gradient-to-br from-indigo-600 to-purple-600 rounded-[2.5rem] flex items-center justify-center shadow-2xl animate-bounce">
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-14 w-14 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
                   </svg>
                </div>
              </div>
              <div className="text-center space-y-3">
                <p className="text-2xl font-magic text-indigo-900">Mixing Magic Ink...</p>
                <p className="text-indigo-400 font-bold max-w-[240px] mx-auto leading-relaxed text-sm tracking-wide uppercase">
                  Painting wonders and waking up the storytellers
                </p>
              </div>
            </div>
          )}

          {state.currentStory && (
            <StoryReader 
              story={state.currentStory} 
              currentIndex={state.currentPageIndex}
              onPageChange={(idx) => setState(prev => ({ ...prev, currentPageIndex: idx }))}
            />
          )}
        </div>
      </main>

      {showInfo && <InfoPanel onClose={() => setShowInfo(false)} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';

interface Props {
  onGenerate: (prompt: string, pageCount: number) => void;
}

const StoryWizard: React.FC<Props> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [isFocused, setIsFocused] = useState(false);
  const [pageCount, setPageCount] = useState(5);

  const suggestions = [
    { text: "A brave kitten who wanted to fly", color: "bg-blue-50 text-blue-700 border-blue-100" },
    { text: "A robot that learned how to garden", color: "bg-green-50 text-green-700 border-green-100" },
    { text: "A journey to the moon made of cheese", color: "bg-yellow-50 text-yellow-700 border-yellow-100" },
    { text: "The secret life of my teddy bear", color: "bg-pink-50 text-pink-700 border-pink-100" }
