  return (
    <div className="w-full max-w-xl animate-[slideUp_0.5s_cubic-bezier(0.16,1,0.3,1)] py-2 sm:py-6">
      <div className="bg-white/90 backdrop-blur-xl rounded-[3rem] p-6 md:p-12 shadow-[0_32px_64px_-16px_rgba(79,70,229,0.15)] border border-white relative overflow-hidden">
        {/* Decorative background blurs */}
        <div className="absolute -top-24 -left-24 w-48 h-48 bg-indigo-200/20 blur-[60px] rounded-full pointer-events-none" />
        <div className="absolute -bottom-24 -right-24 w-48 h-48 bg-purple-200/20 blur-[60px] rounded-full pointer-events-none" />

        <div className="relative z-10">
          <h2 className="text-2xl md:text-4xl font-magic text-indigo-900 mb-2 shimmer-text">
            What shall we imagine?
          </h2>
          <p className="text-indigo-400 font-bold mb-8 text-sm md:text-base tracking-wide uppercase">
            Type an idea or tap a magical path below
          </p>

          <form onSubmit={handleSubmit} className="space-y-8">
            <div className={`group relative transition-all duration-500 rounded-[2.5rem] p-1 ${
              isFocused ? 'bg-gradient-to-br from-indigo-400 to-purple-400 shadow-xl scale-[1.02]' : 'bg-indigo-100/50 hover:bg-indigo-100'
            }`}>
              <div className="bg-white rounded-[2.3rem] overflow-hidden">
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  onFocus={() => setIsFocused(true)}
                  onBlur={() => setIsFocused(false)}
                  placeholder="Tell me a story about..."
                  className="w-full h-32 md:h-40 bg-transparent p-6 text-lg md:text-xl text-indigo-950 placeholder:text-indigo-200 focus:outline-none resize-none font-medium leading-relaxed"
                />
              </div>
            </div>

            <div className="flex flex-wrap gap-2.5 justify-center">
              {suggestions.map((s, i) => (
                <button
                  key={i}
                  type="button"
                  onClick={() => setPrompt(s.text)}
                  className={`px-4 py-2 rounded-xl text-[12px] font-bold transition-all hover:scale-105 active:scale-95 border shadow-sm ${s.color} hover:shadow-md`}
                >
                  {s.text}
                </button>
              ))}
            </div>

            <div className="space-y-4">
              <label className="text-xs font-black text-indigo-300 uppercase tracking-[0.2em] block">
                Story Length
              </label>
              <div className="bg-indigo-50/50 p-2 rounded-[2rem] flex justify-between gap-2 border border-indigo-100/50">
                {pageOptions.map((opt) => (
                  <button
                    key={opt}
                    type="button"
                    onClick={() => setPageCount(opt)}
                    className={`flex-1 py-3 px-2 rounded-[1.5rem] text-sm font-black transition-all duration-300 ${
                      pageCount === opt
                        ? 'bg-white text-indigo-700 shadow-lg scale-105 ring-2 ring-indigo-100'
                        : 'text-indigo-300 hover:text-indigo-500 hover:bg-white/40'
                    }`}
                  >
                    {opt} <span className="text-[10px] opacity-60">PAGES</span>
                  </button>
