            <button
              disabled={!prompt.trim()}
              className={`w-full relative group py-5 rounded-[2.5rem] text-xl font-magic transition-all shadow-2xl overflow-hidden ${
                prompt.trim() 
                  ? 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-200' 
                  : 'bg-indigo-50 text-indigo-200 pointer-events-none'
              }`}
            >
              <span className="relative z-10 flex items-center justify-center gap-3">
                {prompt.trim() && <span className="animate-pulse">✨</span>}
