              </span>
              {prompt.trim() && (
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
              )}
            </button>
          </form>
        </div>
      </div>

      <style>{`
        @keyframes slideUp {
          from { opacity: 0; transform: translateY(30px) scale(0.98); }
          to { opacity: 1; transform: translateY(0) scale(1); }
        }
      `}</style>
    </div>
  );
};

export default StoryWizard;

import React, { useState, useEffect, useRef } from 'react';
import { Story } from '../types';
import { decodeBase64, decodeAudioData } from '../geminiService';

interface Props {
  story: Story;
  currentIndex: number;
  onPageChange: (index: number) => void;
}

const StoryReader: React.FC<Props> = ({ story, currentIndex, onPageChange }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const currentPage = story.pages[currentIndex];
  const totalPages = story.pages.length;

  const handleNext = () => {
    if (currentIndex < totalPages - 1) onPageChange(currentIndex + 1);
  };

  const handlePrev = () => {
    if (currentIndex > 0) onPageChange(currentIndex - 1);
  };

  // Touch handling for swipe
  const touchStartX = useRef<number | null>(null);
  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
  };
  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStartX.current) return;
    const diff = touchStartX.current - e.changedTouches[0].clientX;
    if (diff > 60) handleNext();
    else if (diff < -60) handlePrev();
    touchStartX.current = null;
  };

  const playAudio = async () => {
    if (!currentPage.audioData || isPlaying) return;

    if (currentSourceRef.current) {
      try { currentSourceRef.current.stop(); } catch(e) {}
    }

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }

    const ctx = audioContextRef.current;
    if (ctx.state === 'suspended') await ctx.resume();

    try {
      setIsPlaying(true);
      const data = decodeBase64(currentPage.audioData);
      const buffer = await decodeAudioData(data, ctx, 24000, 1);
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.onended = () => setIsPlaying(false);
      source.start();
      currentSourceRef.current = source;
    } catch (err) {
      console.error("Audio playback error", err);
      setIsPlaying(false);
    }
  };

  useEffect(() => {
    setIsPlaying(false);
    if (currentSourceRef.current) {
      try { currentSourceRef.current.stop(); } catch(e) {}
    }
  }, [currentIndex]);

  return (
    <div 
      className="w-full h-full flex flex-col items-center justify-start sm:justify-center py-2 sm:py-0 perspective-1000"
      onTouchStart={handleTouchStart}
      onTouchEnd={handleTouchEnd}
    >
      <div 
        key={currentIndex}
        className="w-full max-w-[460px] bg-white rounded-[3rem] shadow-[0_40px_80px_-20px_rgba(79,70,229,0.2)] overflow-hidden flex flex-col border border-indigo-50/50 relative page-active"
      >

        {/* Top Image Section - "The Magical Canvas" */}
        <div className="w-full aspect-[4/3] sm:aspect-square bg-indigo-50/30 relative overflow-hidden">
          {currentPage.imageUrl ? (
            <img 
              key={currentPage.imageUrl}
              src={currentPage.imageUrl} 
              alt="Page Illustration" 
              className="w-full h-full object-cover animate-[fadeIn_0.8s_ease-out]"
            />
          ) : (
            <div className="w-full h-full flex flex-col items-center justify-center bg-gradient-to-br from-indigo-50 to-purple-50 p-8 text-indigo-300 relative">
              {/* Sparkle background effects */}
              <div className="sparkle" style={{ top: '20%', left: '30%', animationDelay: '0.1s' }} />
              <div className="sparkle" style={{ top: '60%', left: '70%', animationDelay: '0.5s' }} />
              <div className="sparkle" style={{ top: '40%', left: '80%', animationDelay: '1.2s' }} />

              <div className="relative mb-6">
                <div className="w-16 h-16 border-4 border-indigo-100 border-t-indigo-500 rounded-full animate-spin" />
                <div className="absolute inset-0 flex items-center justify-center">
                  <span className="text-xl animate-pulse">✨</span>
                </div>
              </div>
              <p className="font-magic text-center text-indigo-400 text-sm tracking-widest uppercase">
                Magical artist is painting...
              </p>
            </div>
          )}
          {/* Subtle overlay gradient */}
          <div className="absolute inset-0 bg-gradient-to-t from-black/5 to-transparent pointer-events-none" />
        </div>

        {/* Content Section - "The Living Page" */}
        <div className="flex-1 p-8 sm:p-10 flex flex-col gap-6 paper-texture relative">
          {/* Deckled Edge Effect */}
          <div className="absolute top-0 left-0 right-0 h-2 bg-gradient-to-b from-black/5 to-transparent" />

          <div className="flex justify-between items-start">
            <div className="bg-indigo-600/5 px-3 py-1 rounded-full border border-indigo-100">
              <h3 className="text-indigo-400 font-black text-[9px] uppercase tracking-[0.2em]">
                Page {currentIndex + 1} / {totalPages}
              </h3>
            </div>
            {currentPage.audioData && !isPlaying && (
              <div className="animate-bounce">
                <span className="text-indigo-400 text-[10px] font-bold tracking-tight bg-white px-2 py-1 rounded-lg shadow-sm border border-indigo-50">TAP TO LISTEN</span>
              </div>
            )}
          </div>

          <div className="min-h-[120px] sm:min-h-[160px] flex items-center">
            <p className="text-xl sm:text-2xl font-bold leading-[1.6] text-indigo-950/80 tracking-tight">
              {currentPage.text}
            </p>
          </div>

          <button
            onClick={playAudio}
            disabled={!currentPage.audioData || isPlaying}
            className={`w-full flex items-center justify-center gap-3 py-4 rounded-[2rem] font-magic transition-all shadow-xl active:scale-95 border-b-4 ${
              isPlaying 
                ? 'bg-indigo-50 text-indigo-400 border-indigo-100' 
                : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-200 border-indigo-800 translate-y-[-2px] active:translate-y-[2px]'
            }`}
          >
            {isPlaying ? (
              <div className="flex items-center gap-3">
                <div className="flex gap-1 items-end h-5">
                  <div className="w-1.5 bg-indigo-400 rounded-full animate-[bounce_0.6s_infinite_0s]" />
                  <div className="w-1.5 bg-indigo-400 rounded-full animate-[bounce_0.6s_infinite_0.1s]" />
                  <div className="w-1.5 bg-indigo-400 rounded-full animate-[bounce_0.6s_infinite_0.2s]" />
                </div>
                <span className="text-sm sm:text-base uppercase tracking-widest font-black">Reading aloud...</span>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.983 5.983 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.984 3.984 0 00-1.172-2.828a1 1 0 010-1.415z" clipRule="evenodd" />
                </svg>
                <span className="text-sm sm:text-base tracking-wider">Read to Me</span>
              </div>
            )}
          </button>

          {/* Navigation Controls - The Star Ribbon */}
          <div className="flex justify-between items-center px-2 mt-2">
            <button 
              onClick={handlePrev} 
              disabled={currentIndex === 0}
              className={`text-[10px] font-black tracking-widest transition-all ${currentIndex === 0 ? 'opacity-0 pointer-events-none' : 'text-indigo-300 hover:text-indigo-600 hover:scale-110'}`}
            >
              ← PREV
            </button>

            <div className="flex gap-2.5 items-center">
              {story.pages.map((_, i) => (
                <div 
                  key={i} 
                  className={`rounded-full transition-all duration-500 ${
                    i === currentIndex 
                      ? 'w-4 h-1.5 bg-indigo-600' 
                      : i < currentIndex 
                        ? 'w-1.5 h-1.5 bg-indigo-300' 
                        : 'w-1.5 h-1.5 bg-indigo-100'
                  }`} 
                />
              ))}
            </div>

            <button 
              onClick={handleNext} 
              disabled={currentIndex === totalPages - 1}
              className={`text-[10px] font-black tracking-widest transition-all ${currentIndex === totalPages - 1 ? 'opacity-0 pointer-events-none' : 'text-indigo-300 hover:text-indigo-600 hover:scale-110'}`}
            >
              NEXT →
            </button>
          </div>
        </div>
      </div>

      {/* Footer Hint */}
      <div className="mt-8 flex items-center gap-3 animate-pulse opacity-50">
        <div className="w-10 h-[1px] bg-indigo-200" />
        <p className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.3em]">
          SWIPE TO TURN THE PAGE
        </p>
        <div className="w-10 h-[1px] bg-indigo-200" />
      </div>

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; filter: blur(10px); }
          to { opacity: 1; filter: blur(0); }
        }
        .perspective-1000 {
          perspective: 1000px;
        }
      `}</style>
    </div>
  );
};

export default StoryReader;

import React, { useState, useEffect } from 'react';
import { AppState, Story, ImageSize } from './types';
import LandingPage from './components/LandingPage';
import StoryWizard from './components/StoryWizard';
import StoryReader from './components/StoryReader';
import InfoPanel from './components/InfoPanel';
import { gemini } from './geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    apiKeySelected: false,
    isGenerating: false,
    currentStory: null,
    currentPageIndex: 0,
    imageSize: '1K',
  });

  const [showInfo, setShowInfo] = useState(false);
  const [loadingMessageIdx, setLoadingMessageIdx] = useState(0);

  const loadingMessages = [
    "Mixing Magic Ink...",
    "Whisking up some whimsy...",
    "Dipping brushes in stardust...",
    "Asking the narrator for a story...",
    "Binding the magic pages...",
    "Waking up the characters...",
    "Adding a pinch of wonder..."
  ];

  useEffect(() => {
    let interval: any;
    if (state.isGenerating) {
      interval = setInterval(() => {
        setLoadingMessageIdx((prev) => (prev + 1) % loadingMessages.length);
      }, 2500);
    }
    return () => clearInterval(interval);
  }, [state.isGenerating]);

  useEffect(() => {
    const checkKey = async () => {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (hasKey) setState(prev => ({ ...prev, apiKeySelected: true }));
    };
    checkKey();
  }, []);

  const handleStart = async () => {
    // @ts-ignore
    await window.aistudio.openSelectKey();
    setState(prev => ({ ...prev, apiKeySelected: true }));
  };

  const generateStory = async (userPrompt: string, pageCount: number) => {
    setState(prev => ({ ...prev, isGenerating: true, currentStory: null, currentPageIndex: 0 }));
    try {
      const storyStructure = await gemini.generateStoryStructure(userPrompt, pageCount);
      const firstPage = storyStructure.pages[0];
      const imageUrl = await gemini.generateImage(firstPage.imagePrompt, state.imageSize);
      const audioData = await gemini.generateSpeech(firstPage.text);

      storyStructure.pages[0] = { ...firstPage, imageUrl, audioData };

      setState(prev => ({ 
        ...prev, 
        currentStory: storyStructure, 
        isGenerating: false 
      }));

      loadRemainingPages(storyStructure);
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isGenerating: false }));
      alert("Magic took a nap! Please try again or check your API key.");
    }
  };

  const loadRemainingPages = async (story: Story) => {
    const updatedPages = [...story.pages];
    for (let i = 1; i < updatedPages.length; i++) {
      try {
        const imageUrl = await gemini.generateImage(updatedPages[i].imagePrompt, state.imageSize);
        const audioData = await gemini.generateSpeech(updatedPages[i].text);
        updatedPages[i] = { ...updatedPages[i], imageUrl, audioData };

        setState(prev => {
          if (!prev.currentStory) return prev;
          return { ...prev, currentStory: { ...prev.currentStory, pages: updatedPages } };
        });
      } catch (err) {
        console.warn(`Failed to load page ${i}`, err);
      }
    }
  };

  if (!state.apiKeySelected) {
    return <LandingPage onStart={handleStart} />;
  }

  return (
    <div className="h-full flex flex-col relative overflow-hidden bg-white">
