            <select 
              value={state.imageSize}
              onChange={(e) => setState(prev => ({ ...prev, imageSize: e.target.value as ImageSize }))}
              className="bg-white border border-indigo-100 rounded-full px-4 py-1.5 text-xs font-bold text-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-400 cursor-pointer shadow-sm"
            >
              <option value="1K">1K Quality</option>
              <option value="2K">2K Quality</option>
              <option value="4K">4K Quality</option>
            </select>
          </div>

          <button 
            onClick={() => setShowInfo(!showInfo)}
            className="p-2 md:p-2.5 bg-white border border-indigo-100 rounded-2xl shadow-sm text-indigo-600 hover:shadow-md active:scale-90 transition-all flex items-center justify-center"
            aria-label="App Information"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>
        </div>
      </header>

      <main className="flex-1 relative overflow-y-auto scrollbar-hide px-4 py-2 sm:py-6 md:px-8 flex flex-col items-center">
        <div className="w-full max-w-4xl h-full min-h-0 flex flex-col items-center justify-start sm:justify-center">
          {!state.currentStory && !state.isGenerating && (
            <StoryWizard onGenerate={generateStory} />
          )}

          {state.isGenerating && (
            <div className="flex flex-col items-center justify-center min-h-[400px] w-full max-w-lg relative px-6 py-12">
              {/* Particle System Container */}
              <div className="absolute inset-0 pointer-events-none overflow-hidden">
                {[...Array(12)].map((_, i) => (
                  <div
                    key={i}
                    className="absolute bg-indigo-400/20 rounded-full blur-xl animate-[float_8s_infinite]"
                    style={{
                      width: Math.random() * 60 + 20 + 'px',
                      height: Math.random() * 60 + 20 + 'px',
                      left: Math.random() * 100 + '%',
                      top: Math.random() * 100 + '%',
                      animationDelay: i * 0.7 + 's',
                      opacity: 0.3
                    }}
                  />
                ))}
              </div>

              <div className="relative mb-12">
                {/* Rotating Shimmer Ring */}
                <div className="absolute -inset-6 rounded-[3.5rem] border-2 border-dashed border-indigo-200/50 animate-[spin_20s_linear_infinite]" />

                {/* Main Magic Sphere */}
                <div className="w-32 h-32 md:w-40 md:h-40 bg-gradient-to-br from-indigo-500 via-indigo-600 to-purple-600 rounded-[3rem] flex items-center justify-center shadow-[0_20px_50px_rgba(79,70,229,0.3)] relative group overflow-hidden">
                  {/* Internal Shimmer */}
                  <div className="absolute inset-0 bg-gradient-to-tr from-white/0 via-white/20 to-white/0 translate-x-[-100%] animate-[shimmer_3s_infinite]" />

                  <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 md:h-20 md:w-20 text-white relative z-10 animate-[float_4s_ease-in-out_infinite]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
                  </svg>

                  {/* Floating sparkles inside the box */}
                  <span className="absolute top-4 right-4 text-white/50 text-xl animate-pulse">✨</span>
                  <span className="absolute bottom-4 left-4 text-white/50 text-lg animate-pulse" style={{ animationDelay: '1s' }}>✨</span>
                </div>
              </div>

              <div className="text-center space-y-4 relative z-10">
