              </div>

              {/* Progress Bar placeholder (visual only) */}
              <div className="mt-12 w-48 h-1.5 bg-indigo-100 rounded-full overflow-hidden">
                <div className="h-full bg-indigo-500 rounded-full animate-[progress_3s_infinite_ease-in-out]" style={{ width: '40%' }} />
              </div>
            </div>
          )}

          {state.currentStory && (
            <StoryReader 
              story={state.currentStory} 
              currentIndex={state.currentPageIndex}
              onPageChange={(idx) => setState(prev => ({ ...prev, currentPageIndex: idx }))}
            />
          )}
        </div>
      </main>

      {showInfo && <InfoPanel onClose={() => setShowInfo(false)} />}

      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0px) rotate(0deg); }
