import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Story, ImageSize } from "./types";

// Helper to decode base64 to bytes
export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Helper to decode PCM data
export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export class GeminiService {
  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async generateStoryStructure(prompt: string, pageCount: number = 5): Promise<Story> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Sukurkite žavingą pasaką vaikams pagal šią idėją: "${prompt}". 
      ISTORIJA PRIVALO BŪTI PARAŠYTA LIETUVIŲ KALBA.
      Grąžinkite istoriją kaip JSON objektą su pavadinimu ir lygiai ${pageCount} puslapiais. 
      Kiekvienas puslapis turi turėti "text" (daugiausiai 3 sakiniai) ir "imagePrompt" (išsamus angliškas aprašymas iliustracijai sukurti, skirtas kid-friendly stiliui).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            pages: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  imagePrompt: { type: Type.STRING }
                },
                required: ["text", "imagePrompt"]
              }
            }
          },
          required: ["title", "pages"]
        }
      }
    });

    return JSON.parse(response.text || '{}') as Story;
  }

  async generateImage(prompt: string, size: ImageSize): Promise<string> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [{ text: `A magical children's book illustration: ${prompt}. Soft colors, high quality, whimsical style.` }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: size
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("Failed to generate image");
  }

  async generateSpeech(text: string): Promise<string> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Perskaityk šį pasakos puslapį šiltu, draugišku ir išraiškingu balsu lietuvių kalba: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' } 
          }
        }
      }
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Failed to generate speech");
    return base64Audio;
  }

  async chatWithGemini(userMessage: string, chatHistory: any[]): Promise<string> {
    const ai = this.getAI();
    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: {
        systemInstruction: "Esate draugiškas, stebuklingas pasakų knygos pagalbininkas. Atsakykite į vaikų klausimus apie istorijas ir magiją maloniai, paprastai ir drąsinančiai lietuvių kalba. Atsakymai turi būti trumpi ir mieli.",
      }
    });

    const response = await chat.sendMessage({ message: userMessage });
    return response.text || "Nežinau ką pasakyti, bet džiaugiuosi būdamas čia!";
  }
}

